Solution for technical screen question: https://leetcode.com/problems/shortest-way-to-form-string/

```
def numAppends(s, t):
    if t == "":
        return 0
    ans = 0
    next_occ = {i: [-1 for _ in range(26)] for i in range(len(s))}
    for i in range(len(s) - 1, -1, -1):
        if i != len(s) - 1:
            for j, k in enumerate(next_occ[i + 1]):
                if k != -1:
                    next_occ[i][j] = k
        next_occ[i][ord(s[i]) - ord('a')] = i

    i = 0
    j = 0
    while j != len(t):
        new_i = next_occ[i][ord(t[j]) - ord('a')]
        if new_i == -1 and i != 0:
            i = 0
            ans += 1
        elif new_i == -1:
            return -1
        else:
            i = new_i + 1
            j += 1
        if i >= len(s) and j != len(t):
            i = 0
            ans += 1
    return ans
